<template>
  <div class="histogram">    
    <div v-if="!data">
      <p>No available data.</p>
    </div>

    <div
      v-else
      id="chart-div"
    />

  </div>
</template>

<script>
import * as d3 from 'd3'

export default {
  name: 'Histogram1D',
  props: {
    data: {
      type: Object,
      default: null
    },
    ordinals: {
      type: Object,
      default: null
    }    
  },
  components: {
  },  
  data () {
    return {
      settings: {
        sizeX: 950,
        sizeY: 750,
        contextHeight: 550,
        canvasX: 1000,
        canvasY: 700,
        height2: 60,
        margin: {
            top: 50,
            right: 100,
            bottom: 50,
            left: 100
        }       
      }
    }
  },

  beforeCreate () {
  },

  created () {
  },

  beforeMount () {
  },

  mounted () {
    this.renderChart();
  },

  beforeUnmount () {
  },

  unmounted () {
  },

  updated () {
  },

  beforeUpdate () {
  },

  activated () {
  },

  deactivated () {  
  },

  methods: {
    renderChart () {
      console.log("renderChart ()")

      var vm = this

      const svg = d3.select('#chart-div')
                    .append('svg')
                    .attr('width', this.settings.sizeX)
                    .attr('height', this.settings.sizeY)

      const focus = svg.append('g')
                    .attr('class', 'focus')
                    .attr('transform', `translate(${this.settings.margin.left}, ${this.settings.margin.top})`)

      const context = svg.append('g')
                        .attr('class', 'context')
                        .attr('transform', `translate(${this.settings.margin.left}, ${this.settings.margin.top + this.settings.contextHeight})`)

      // the scale
      let x1 = d3.scaleLinear().range([0, this.width])
      let y1 = d3.scaleLinear().range([this.height, 0])
      let x2 = d3.scaleLinear().range([0, this.width])      
      let y2 = d3.scaleLinear().range([this.settings.height2, 0])

      let xBand = d3.scaleBand().domain(d3.range(-1, this.ordinals.length)).range([0, this.width])

      let xAxis = d3.axisBottom(x1).tickFormat((d, e) => this.ordinals[d]) // eslint-disable-line no-unused-vars
      // let xAxis2 = d3.axisBottom(x2) // eslint-disable-line no-unused-vars
      let yAxis = d3.axisLeft(y1)
      // let yAxis2 = d3.axisLeft(y2)

      // 1D brush for data selection
      let brush = d3.brushX()
          .extent([[0, 0], [this.width, this.settings.height2]])
          .on("start", brushstarted)
          .on("brush", brushed)
          .on("end", brushended)

      x1.domain([-1, this.ordinals.length])
      y1.domain([0, d3.max(this.data, d => d.value)])      
      x2.domain(x1.domain())      
      y2.domain([0, d3.max(this.data, d => d.value)])

      // main chart
      var chart = focus.append('g')
          .attr('clip-path','url(#my-clip-path)')
          .selectAll('.unselectedStyle')
          .data(this.data)
          .enter()
          .append('rect')
          .attr('class', 'unselectedStyle')
          .attr('x', (d, i) => {
            return x1(i) - xBand.bandwidth()*0.9/2
          })
          .attr('y', (d, i) => { // eslint-disable-line no-unused-vars
            return y1(d.value)
          })
          .attr('width', xBand.bandwidth()*0.9)
          .attr('height', d => {
            return this.height - y1(d.value)
          })

      // add x-axis
      focus.append('g')
            .attr('class', 'axis')
            .attr('transform', `translate(0,${this.height})`)
            .call(xAxis)

      // add y-axis
      focus.append('g')
            .attr('class', 'axis axis--y')
            .call(yAxis)

      focus.append("text")
          // .attr("x", (this.chartWidth / 2))             
          // .attr("y", 0 - (this.settings.margin.bottom / 2))
          .attr("x", this.width / 2)          
          .attr("y", this.height - this.settings.contextHeight)          
          .attr("text-anchor", "middle")  
          .style("font-size", "24px") 
          // .style("text-decoration", "underline")  
          .text("1D Histogram");


      let defs = focus.append('defs')

      // use clipPath
      defs.append('clipPath')
          .attr('id', 'my-clip-path')
          .append('rect')
          .attr('width', this.width)
          .attr('height', this.height)

      // overview chart
      context.selectAll('.barStyle')
          .data(this.data)
          .enter()
          .append('rect')
          .attr('class', 'barStyle')
          .attr('x', (d, i) => {
            return x2(i) - xBand.bandwidth()*0.9/2
          })
          .attr('y', (d, i) => y2(d.value)) // eslint-disable-line no-unused-vars
          .attr('width', xBand.bandwidth()*0.9)
          .attr('height', d => {
            return this.settings.height2 - y2(d.value)
          })

      context.append("text")
          // .attr("x", (this.chartWidth / 2))             
          // .attr("y", 0 - (this.settings.margin.bottom / 2))
          .attr("x", this.width / 2)          
          .attr("y", this.settings.height2 + this.settings.margin.bottom)          
          .attr("text-anchor", "middle")  
          .style("font-size", "20px") 
          // .style("text-decoration", "underline") 
          .text("Data filter");

      context.append('g')
            .attr('class', 'axis2')
            .attr('transform', `translate(0,${this.settings.height2})`)
            .call(xAxis)

      context.append('g')
            .attr('class', 'brush')
            .call(brush)
            .call(brush.move, x1.range())

      // change chart scale when brush is used
      function brushed() {
        // var selection = d3.event.selection || x2.range()
        // x.domain(selection.map(x2.invert, x2))
        // focus.select('.axis').call(xAxis)
        // focus.selectAll('.bar').attr('x', (d, i) => {
        //       console.log("i :", i, " x(i) :", x(i), " d :",d)
        //       return x(i) - xBand.bandwidth()*0.9/2
        // })

        // console.log(selection[0], selection[1])

        // // focus.selectAll('.bar').attr('x', (d, i) => {
        // //     console.log("points: ",i, x(i))
        // //     // return x(i) - xBand.bandwidth()*0.9/2
        // //     // return x0 <= cx && cx <= x1;
        // //     // return x0 <= cx && cx <= x1 && y0 <= cy && cy <= y1            

        // // })

      }


      // Clear the previously-active brush, if any.
      function brushstarted() {
        // if (brushCell !== this) {
        //   d3.select(brushCell).call(brush.move, null);
        //   brushCell = this;
        // }
      }

      // // Highlight the selected circles.
      // function brushed() {
      //   // if (d3.event.selection === null) return;
      //   // const [[x0, y0], [x1, y1]] = d3.event.selection; 
      //   // circle.classed("hidden", d => {
      //   //   return x0 > x[i](d[columns[i]])
      //   //       || x1 < x[i](d[columns[i]])
      //   //       || y0 > y[j](d[columns[j]])
      //   //       || y1 < y[j](d[columns[j]]);
      //   // });

      //   if (d3.event.selection === null) return;
      //   const [xCoor, yCoor] = d3.event.selection; 
      //   console.log(xCoor, yCoor)
      //   console.log(x[xCoor])


      //   // var extent = brush.extent();
      //   // console.log(extent[0])
      //   // var x0 = extent[0][0],
      //   //     y0 = extent[0][1],
      //   //     x1 = extent[1][0],
      //   //     y1 = extent[1][1];
      //   // console.log(x0, y0, x1, y1)

      // }

      // If the brush is empty, select all circles.
      function brushended() {

        var extent = d3.event.selection || x2.range()

        var selectedData = []
        chart.classed("selected", function(d,i) {    
          // // return isBrushed(extent, x(d.value) ) 

          var brushStatus = isBrushed(extent, x1(i))

          if (brushStatus) {
            // console.log(i)          
            // console.log(x2(d.value))
            // console.log(d.value)
            // console.log(d.city)

            // selectedData.push(d[vm.dataFields[1]])
            selectedData.push(d)            

          }

          return brushStatus
        })

        vm.$emit('data-filtered', selectedData)

      }

      // A function that return TRUE or FALSE according if a dot is in the selection or not
      function isBrushed(brush_coords, cx) {
          var x0 = brush_coords[0],
              x1 = brush_coords[1];
          return x0 <= cx && cx <= x1;    // This return TRUE or FALSE depending on if the points is in the selected area
      } 

    }

  },

  computed: {
    width: function () {
      return this.settings.canvasX - this.settings.margin.left - this.settings.margin.right
    },

    height: function () {
      return this.settings.canvasY - this.settings.margin.top - this.settings.margin.bottom - 80
    },

    dataFields: function () {
      // for (const [key, value] of Object.entries(this.data[0])) {
      //   console.log(`${key}: ${value}`);
      // }
      return Object.keys(this.data[0])

    }
  },

  watch: {
    data: {
      handler: function() {
          d3.select("svg").remove();
          this.renderChart();
      },
      immediate: true
    }
  }

}
</script>

<style>

  .unselectedStyle {
    fill: lightgrey;
  }

  .barStyle {
    fill: dimgray;
  }

  .selected {
    opacity: 1 !important;
    stroke: black;
    stroke-width: 1px;
    fill: rgb(30, 161, 47);
  }

</style>